import { Flex, Grid, Image, Text, Box, Heading } from "@chakra-ui/react";

const categories = [
  {
    name: "Data Science",
    courses: 425,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/data_science.png",
  },
  {
    name: "Business",
    courses: 1395,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/business.png",
  },
  {
    name: "Computer Science",
    courses: 668,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/computer_science.png",
  },
  {
    name: "Health",
    courses: 471,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/social_sciences.png",
  },
  {
    name: "Personal Development",
    courses: 300,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/personal_development.png",
  },
  {
    name: "Arts & Humanities",
    courses: 666,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/arts_and_humanities.png",
  },
  {
    name: "Engineering",
    courses: 338,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/physical_science_and_engineering.png",
  },
  {
    name: "Language Learning",
    courses: 150,
    img: "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://s3.amazonaws.com/coursera_assets/browse/domains/language_learning.png",
  },
];

const Section5 = () => {
  return (
    <Box py={16} px={5}>
      {/* HEADER */}
      <Heading size="lg" mb={8}>
        Explore top categories
      </Heading>

      {/* GRID */}
      <Grid
        templateColumns={{
          base: "repeat(2, 1fr)",
          md: "repeat(3, 1fr)",
          lg: "repeat(4, 1fr)",
        }}
        gap={6}
      >
        {categories.map((cat, index) => (
          <Box
            key={index}
            p={5}
            borderRadius="lg"
            border="1px solid #eee"
            bg="white"
            _hover={{
              transform: "translateY(-5px)",
              boxShadow: "lg",
              transition: "0.3s",
              cursor: "pointer",
            }}
          >
            <Flex direction="column" align="center" gap={3}>
              <Image
                src={cat.img}
                alt={cat.name}
                boxSize="60px"
                objectFit="contain"
              />

              <Text fontWeight="bold" textAlign="center">
                {cat.name}
              </Text>

              <Text fontSize="sm" color="gray.500">
                {cat.courses} courses
              </Text>
            </Flex>
          </Box>
        ))}
      </Grid>
    </Box>
  );
};

export default Section5;
